from flask import Flask, jsonify
import pymemcache
from flask_sqlalchemy import SQLAlchemy
from functools import wraps

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///db.sqlite'
app.config['MEMCACHE_SERVERS'] = 'localhost:11211'

# Initialize Memcached client
memcached_client = pymemcache.Client([(app.config['MEMCACHE_SERVERS'], 1)])

db = SQLAlchemy(app)


def cache_result(ttl):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            key = f"{func.__name__}:{args}:{kwargs}"
            result = memcached_client.get(key)
            if result is not None:
                return result
            else:
                result = func(*args, **kwargs)
                memcached_client.set(key, result, ttl=ttl)
                return result
        return wrapper
    return decorator


@app.route('/users', methods=['GET'])
@cache_result(ttl=60)  # cache for 1 minute
def get_users():
    users = db.session.query(User).all()
    return jsonify([user.to_dict() for user in users])


class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(100), nullable=False)

    def to_dict(self):
        return {'id': self.id, 'name': self.name}


if __name__ == '__main__':
    with app.app_context():
        db.create_all()
    app.run(debug=True)